import React, { useState } from "react";
import API from "../services/api";

function Login() {

  const [email,setEmail] =
  useState("");

  const [password,setPassword] =
  useState("");

  const submitHandler =
  async(e)=>{

    e.preventDefault();

    try{

      const res =
      await API.post(
        "/auth/login",
        {
          email,
          password
        }
      );

      localStorage.setItem(
        "token",
        res.data.token
      );

      alert("Login Success");

    }catch(error){

      alert("Login Failed");

    }

  };

  return (

    <div className="container mt-5">

      <div className="row justify-content-center">

        <div className="col-md-5">

          <div className="card p-4 shadow">

            <h2 className="mb-4">
              Login
            </h2>

            <form
              onSubmit={submitHandler}
            >

              <input
                type="email"
                className="form-control mb-3"
                placeholder="Email"
                onChange={(e)=>
                setEmail(
                  e.target.value
                )}
              />

              <input
                type="password"
                className="form-control mb-3"
                placeholder="Password"
                onChange={(e)=>
                setPassword(
                  e.target.value
                )}
              />

              <button
                className="btn btn-primary w-100"
              >
                Login
              </button>

            </form>

          </div>

        </div>

      </div>

    </div>

  );

}

export default Login;
